function solve(nums, k) {
    if (nums.length === 1) {
        return 0;
    }

    // Sort the array to easily find min and max
    nums.sort((a, b) => a - b);

    // We need to find the smallest number of elements to remove so that the remaining array is balanced
    // We can try all possible subarrays and check if they are balanced
    // Since the array can be large, we need an efficient approach

    // The optimal approach is to consider all possible subarrays where the first and last elements are the min and max
    // and check if the max is at most k times the min

    let minRemove = nums.length - 1; // Worst case: remove all but one element

    for (let i = 0; i < nums.length; i++) {
        for (let j = i + 1; j < nums.length; j++) {
            // Check if the subarray from i to j is balanced
            if (nums[j] <= nums[i] * k) {
                // The subarray from i to j is balanced, so we can keep it
                // The number of elements to remove is (nums.length - (j - i + 1))
                minRemove = Math.min(minRemove, nums.length - (j - i + 1));
                break; // No need to check longer subarrays
            }
        }
    }

    return minRemove;
}

